unit lipdecide;

{$mode objfpc}{$H+}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

const
  SIX_DIGIT_FACTOR = 100000.0;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  A_scaled, B_scaled: real;
  A_int, B_int: longint;
begin
  A_scaled := A * SIX_DIGIT_FACTOR;
  B_scaled := B * SIX_DIGIT_FACTOR;
  A_int := round(A_scaled);
  B_int := round(B_scaled);
  if A_int < B_int then
    REALCOMPARE := LT
  else if A_int > B_int then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

function Quadrant(x, y: real): integer;
begin
  if (x >= 0) and (y >= 0) then
    Quadrant := 1
  else if (x < 0) and (y >= 0) then
    Quadrant := 2
  else if (x < 0) and (y < 0) then
    Quadrant := 3
  else
    Quadrant := 4;
end;

function CircleCircumference(x1, y1, x2, y2, x3, y3: real; var cx, cy, cr: real): boolean;
var
  d, ux, uy, vx, vy: real;
begin
  d := 2 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
  if abs(d) < 1e-12 then
  begin
    CircleCircumference := false;
    exit;
  end;
  ux := ((sqr(x1) + sqr(y1)) * (y2 - y3) + (sqr(x2) + sqr(y2)) * (y3 - y1) + (sqr(x3) + sqr(y3)) * (y1 - y2)) / d;
  uy := ((sqr(x1) + sqr(y1)) * (x3 - x2) + (sqr(x2) + sqr(y2)) * (x1 - x3) + (sqr(x3) + sqr(y3)) * (x2 - x1)) / d;
  cx := ux;
  cy := uy;
  cr := Distance(ux, uy, x1, y1);
  CircleCircumference := true;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  num, denom: real;
begin
  if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) then
    PointToLineDistance := Distance(px, py, x1, y1)
  else
  begin
    num := abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1);
    denom := sqrt(sqr(y2 - y1) + sqr(x2 - x1));
    if REALCOMPARE(denom, 0) = EQ then
      PointToLineDistance := Distance(px, py, x1, y1)
    else
      PointToLineDistance := num / denom;
  end;
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2;
end;

function AngleAtVertex(x1, y1, x2, y2, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y: real;
  dot, mag1, mag2, cosAngle: real;
begin
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;
  dot := v1x * v2x + v1y * v2y;
  mag1 := sqrt(sqr(v1x) + sqr(v1y));
  mag2 := sqrt(sqr(v2x) + sqr(v2y));
  if (REALCOMPARE(mag1, 0) = EQ) or (REALCOMPARE(mag2, 0) = EQ) then
  begin
    AngleAtVertex := -1;
    exit;
  end;
  cosAngle := dot / (mag1 * mag2);
  if cosAngle > 1 then
    cosAngle := 1
  else if cosAngle < -1 then
    cosAngle := -1;
  AngleAtVertex := arccos(cosAngle);
end;

procedure EvaluateLIC1;
var
  i: integer;
  dist: real;
begin
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC2;
var
  i: integer;
  cx, cy, cr: real;
begin
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if CircleCircumference(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], cx, cy, cr) then
    begin
      if REALCOMPARE(cr, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[2] := true;
        exit;
      end;
    end
    else
    begin
      CMV[2] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC3;
var
  i: integer;
  angle: real;
begin
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := AngleAtVertex(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if angle >= 0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC5;
var
  i, j, q: integer;
  quadSet: set of 1..4;
begin
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quadSet := [];
    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      q := Quadrant(X[i + j], Y[i + j]);
      quadSet := quadSet + [q];
    end;
    if card(quadSet) > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC6;
var
  i: integer;
begin
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC7;
var
  i, j: integer;
  dist: real;
begin
  CMV[7] := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    for j := 1 to PARAMETERS.N_PTS do
    begin
      dist := PointToLineDistance(X[i + j - 1], Y[i + j - 1], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
      if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
      begin
        CMV[7] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC8;
var
  i: integer;
  dist: real;
begin
  CMV[8] := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC9;
var
  i: integer;
  cx, cy, cr: real;
begin
  CMV[9] := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if CircleCircumference(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                           X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                           cx, cy, cr) then
    begin
      if REALCOMPARE(cr, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[9] := true;
        exit;
      end;
    end
    else
    begin
      CMV[9] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC10;
var
  i: integer;
  angle: real;
begin
  CMV[10] := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    angle := AngleAtVertex(X[i], Y[i],
                           X[i + PARAMETERS.C_PTS + 1], Y[i + PARAMETERS.C_PTS + 1],
                           X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2]);
    if angle >= 0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[10] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC11;
var
  i: integer;
  area: real;
begin
  CMV[11] := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i],
                         X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                         X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[11] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC12;
var
  i: integer;
begin
  CMV[12] := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then
    begin
      CMV[12] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC13;
var
  i: integer;
  dist: real;
  hasGreater, hasLess: boolean;
begin
  CMV[13] := false;
  if NUMPOINTS < 3 then
    exit;
  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      hasGreater := true;
    if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
      hasLess := true;
  end;
  CMV[13] := hasGreater and hasLess;
end;

procedure EvaluateLIC14;
var
  i: integer;
  cx, cy, cr: real;
  hasOutside, hasInside: boolean;
begin
  CMV[14] := false;
  if NUMPOINTS < 5 then
    exit;
  hasOutside := false;
  hasInside := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if CircleCircumference(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                           X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                           cx, cy, cr) then
    begin
      if REALCOMPARE(cr, PARAMETERS.RADIUS1) = GT then
        hasOutside := true;
      if REALCOMPARE(cr, PARAMETERS.RADIUS2) = LT then
        hasInside := true;
    end
    else
      hasOutside := true;
  end;
  CMV[14] := hasOutside and hasInside;
end;

procedure EvaluateLIC15;
var
  i: integer;
  area: real;
  hasGreater, hasLess: boolean;
begin
  CMV[15] := false;
  if NUMPOINTS < 5 then
    exit;
  hasGreater := false;
  hasLess := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i],
                         X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                         X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      hasGreater := true;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      hasLess := true;
  end;
  CMV[15] := hasGreater and hasLess;
end;

procedure ComputePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        PUM[i, j] := true
      else
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure ComputeLAUNCH;
var
  i: integer;
begin
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      exit;
    end;
  end;
end;

procedure DECIDE;
begin
  EvaluateLIC1;
  EvaluateLIC2;
  EvaluateLIC3;
  EvaluateLIC4;
  EvaluateLIC5;
  EvaluateLIC6;
  EvaluateLIC7;
  EvaluateLIC8;
  EvaluateLIC9;
  EvaluateLIC10;
  EvaluateLIC11;
  EvaluateLIC12;
  EvaluateLIC13;
  EvaluateLIC14;
  EvaluateLIC15;

  ComputePUM;
  ComputeFUV;
  ComputeLAUNCH;
end;

end.
